# Utility module - helper functions and constants
from shapes import Shape

PI_SQUARED: float = 9.8696

def format_number(n: float) -> str:
    return f"{n:.2f}"

def sum_areas(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total

def count_by_name(shapes: list[Shape], name: str) -> int:
    count: int = 0
    for s in shapes:
        if s.name == name:
            count = count + 1
    return count
